previewCss:
.darma-loader-uiverse-jumping-soft-cube {
  width: 48px;
  height: 48px;
  margin: auto;
  position: relative;
}

.darma-loader-uiverse-jumping-soft-cube:before {
content: '';
width: 48px;
height: 5px;
background: #f0808050;
position: absolute;
top: 60px;
left: 0;
border-radius: 50%;
animation: darma-loader-uiverse-jumping-soft-cube-shadow324 0.5s linear infinite;
}

.darma-loader-uiverse-jumping-soft-cube:after {
content: '';
width: 100%;
height: 100%;
background: #f08080;
position: absolute;
top: 0;
left: 0;
border-radius: 4px;
animation: darma-loader-uiverse-jumping-soft-cube-jump7456 0.5s linear infinite;
}

@keyframes darma-loader-uiverse-jumping-soft-cube-jump7456 {
15% {
border-bottom-right-radius: 3px;
}

25% {
transform: translateY(9px) rotate(22.5deg);
}

50% {
transform: translateY(18px) scale(1, .9) rotate(45deg);
border-bottom-right-radius: 40px;
}

75% {
transform: translateY(9px) rotate(67.5deg);
}

100% {
transform: translateY(0) rotate(90deg);
}
}

@keyframes darma-loader-uiverse-jumping-soft-cube-shadow324 {

0%,
100% {
transform: scale(1, 1);
}

50% {
transform: scale(1.2, 1);
}
}

